import React, { useState, useEffect, useRef } from 'react';

const Skills = () => {
  const [hoveredSkill, setHoveredSkill] = useState(null);
  const containerRef = useRef(null);
  const [rotation, setRotation] = useState(0);

  const allSkills = [
    { name: 'HTML5', icon: '🌐' },
    { name: 'CSS3', icon: '🎨' },
    { name: 'JavaScript', icon: '⚡' },
    { name: 'TypeScript', icon: '📘' },
    { name: 'React', icon: '⚛️' },
    { name: 'Next.js', icon: '▲' },
    { name: 'Tailwind CSS', icon: '💨' },
    { name: 'Redux', icon: '🔄' },
    { name: 'Framer Motion', icon: '🎬' },
    { name: 'Node.js', icon: '🟢' },
    { name: 'Express.js', icon: '🚀' },
    { name: 'MongoDB', icon: '🍃' },
    { name: 'MySQL', icon: '🐬' },
    { name: 'PostgreSQL', icon: '🐘' },
    { name: 'Firebase', icon: '🔥' },
    { name: 'JWT', icon: '🔐' },
    { name: 'REST API', icon: '🔗' },
    { name: 'Socket.io', icon: '📡' },
    { name: 'Java', icon: '☕' },
    { name: 'Python', icon: '🐍' },
    { name: 'C++', icon: '⚙️' },
    { name: 'C', icon: '🔧' },
    { name: 'C#', icon: '🎯' },
    { name: 'PHP', icon: '🐘' },
    { name: 'Git', icon: '🔀' },
    { name: 'GitHub', icon: '🐙' },
    { name: 'Docker', icon: '🐳' },
    { name: 'Linux', icon: '🐧' },
    { name: 'VS Code', icon: '💻' },
    { name: 'Postman', icon: '📮' },
    { name: 'Figma', icon: '🎯' }
  ];

  // Fan rotation animation - slow motion
  useEffect(() => {
    const interval = setInterval(() => {
      setRotation(prev => (prev + 0.3) % 360);
    }, 50); // 50ms = smooth slow rotation

    return () => clearInterval(interval);
  }, []);

  return (
    <section id="skills" className="relative z-10 py-16 px-6 overflow-hidden min-h-screen">
      <div className="max-w-6xl mx-auto">
        <h2 className="text-sm uppercase tracking-widest text-gray-500 font-semibold mb-8">My Skills</h2>

        <div 
          ref={containerRef}
          className="relative min-h-[600px] w-full flex items-center justify-center"
        >
          {/* Background Glow */}
          <div className="absolute w-[500px] h-[500px] rounded-full bg-purple-500/5 blur-3xl"></div>

          {/* Skills Container - Fan Rotation */}
          <div 
            className="relative w-full h-full flex items-center justify-center"
            style={{
              transform: `rotate(${rotation}deg)`,
              transition: 'transform 0.05s linear'
            }}
          >
            {/* Center Dot */}
            <div className="absolute w-4 h-4 rounded-full bg-purple-500/50 animate-pulse z-20"></div>

            {/* Skills in Fan Layout */}
            {allSkills.map((skill, index) => {
              const total = allSkills.length;
              const angle = (index / total) * 360;
              const radius = 180 + (index % 3) * 30; // Different radius for depth effect
              const rad = (angle * Math.PI) / 180;
              const x = Math.cos(rad) * radius;
              const y = Math.sin(rad) * radius;

              return (
                <div
                  key={skill.name}
                  className="absolute cursor-pointer transition-all duration-300"
                  style={{
                    transform: `translate(${x}px, ${y}px)`,
                    zIndex: hoveredSkill === skill.name ? 50 : 10
                  }}
                  onMouseEnter={() => setHoveredSkill(skill.name)}
                  onMouseLeave={() => setHoveredSkill(null)}
                >
                  <div
                    className="flex flex-col items-center justify-center rounded-full transition-all duration-300"
                    style={{
                      width: hoveredSkill === skill.name ? '80px' : '58px',
                      height: hoveredSkill === skill.name ? '80px' : '58px',
                      boxShadow: hoveredSkill === skill.name 
                        ? '0 0 60px rgba(139,92,246,0.4), 0 0 120px rgba(139,92,246,0.15)' 
                        : 'none',
                      background: hoveredSkill === skill.name 
                        ? 'rgba(26,31,46,0.9)' 
                        : 'rgba(26,31,46,0.2)',
                      border: hoveredSkill === skill.name 
                        ? '1.5px solid rgba(139,92,246,0.5)' 
                        : '1px solid rgba(255,255,255,0.05)',
                      transform: hoveredSkill === skill.name ? 'scale(1.2)' : 'scale(1)'
                    }}
                  >
                    <span
                      className="transition-all duration-300"
                      style={{
                        fontSize: hoveredSkill === skill.name ? '30px' : '20px',
                        filter: hoveredSkill === skill.name 
                          ? 'brightness(1.3) drop-shadow(0 0 20px rgba(139,92,246,0.3))' 
                          : 'brightness(0.8)'
                      }}
                    >
                      {skill.icon}
                    </span>

                    {hoveredSkill === skill.name && (
                      <span className="text-[9px] font-semibold text-white mt-0.5 animate-fadeIn">
                        {skill.name}
                      </span>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Stats */}
        <div className="grid grid-cols-2 md:grid-cols-5 gap-4 mt-8 glass-card rounded-2xl p-6">
          <div className="text-center">
            <div className="text-2xl font-bold text-white">2</div>
            <div className="text-[10px] text-gray-500">Projects Completed</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">-</div>
            <div className="text-[10px] text-gray-500">Happy Clients</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">-</div>
            <div className="text-[10px] text-gray-500">Years Experience</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">200</div>
            <div className="text-[10px] text-gray-500">Cups of Coffee</div>
          </div>
          <div className="text-center">
            <div className="text-2xl font-bold text-white">5</div>
            <div className="text-[10px] text-gray-500">Technologies Mastered</div>
          </div>
        </div>

        <div className="text-center text-gray-500 text-xs mt-4 opacity-60">
          Hover on any skill to see more ✨
        </div>
      </div>

      <style>{`
        @keyframes fadeIn {
          from {
            opacity: 0;
            transform: scale(0.8);
          }
          to {
            opacity: 1;
            transform: scale(1);
          }
        }
        .animate-fadeIn {
          animation: fadeIn 0.25s ease-out forwards;
        }
        .animate-pulse {
          animation: pulse 2s ease-in-out infinite;
        }
        @keyframes pulse {
          0%, 100% { transform: scale(1); opacity: 0.5; }
          50% { transform: scale(1.5); opacity: 1; }
        }
        .glass-card {
          background: rgba(17, 17, 17, 0.4);
          backdrop-filter: blur(10px);
          border: 1px solid rgba(255, 255, 255, 0.03);
          transition: all 0.3s ease;
        }
        .glass-card:hover {
          border-color: rgba(139, 92, 246, 0.1);
        }
      `}</style>
    </section>
  );
};

export default Skills;
